import { useMemo } from "react";
import { type Knob, type KnobGroup } from "@imfusion/web-ui";

import { KnobSection } from "./knob-section/knob-section";
import { KnobSlider } from "./knob-slider/knob-slider";

import classes from "./knob-panel.module.css";

interface Props {
  knobs: readonly Knob[];
  overrides: Record<string, number>;
  onChange: (knobId: string, value: number) => void;
}

const SECTIONS: { group: KnobGroup; title: string }[] = [
  { group: "surfaces", title: "Surfaces" },
  { group: "intents", title: "Intents" },
  { group: "foregrounds", title: "Foregrounds" }
];

export function KnobPanel({ knobs, overrides, onChange }: Props) {
  const grouped = useMemo(() => {
    const map = new Map<KnobGroup, Knob[]>();
    for (const k of knobs) {
      const list = map.get(k.group) ?? [];
      list.push(k);
      map.set(k.group, list);
    }
    return map;
  }, [knobs]);

  return (
    <div className={classes.root}>
      {SECTIONS.map(({ group, title }) => {
        const items = grouped.get(group);
        if (!items || items.length === 0) return null;
        return (
          <KnobSection key={group} title={title}>
            {items.map(knob => (
              <KnobSlider
                key={knob.id}
                label={knob.label}
                value={overrides[knob.cssVar] ?? knob.defaultValue}
                min={knob.min}
                max={knob.max}
                step={knob.step}
                onChange={value => onChange(knob.id, value)}
              />
            ))}
          </KnobSection>
        );
      })}
    </div>
  );
}

import { SliderRoot, SliderControl, SliderTrack, SliderIndicator, SliderThumb } from "@imfusion/web-ui";

import classes from "./knob-slider.module.css";

interface Props {
  label: string;
  value: number;
  min: number;
  max: number;
  step: number;
  onChange: (value: number) => void;
}

export function KnobSlider({ label, value, min, max, step, onChange }: Props) {
  const displayValue = step >= 1 ? String(value) : value.toFixed(3);

  return (
    <div className={classes.root}>
      <div className={classes.header}>
        <span className={classes.label}>{label}</span>
        <span className={classes.value}>{displayValue}</span>
      </div>
      <SliderRoot value={value} min={min} max={max} step={step} onValueChange={v => onChange(Array.isArray(v) ? v[0] : v)}>
        <SliderControl>
          <SliderTrack>
            <SliderIndicator />
            <SliderThumb aria-label={label} />
          </SliderTrack>
        </SliderControl>
      </SliderRoot>
    </div>
  );
}

