  { group: "surfaces", title: "Surfaces" },
  { group: "intents", title: "Intents" },
  { group: "foregrounds", title: "Foregrounds" }
];

const PAIR_PREFIX_RE = /^(.+) \u2014 /;

function groupIntoPairs(items: Knob[]): { label: string; knobs: Knob[] }[] {
  const groups: { label: string; knobs: Knob[] }[] = [];
  let i = 0;
  while (i < items.length) {
    const prefix = items[i].label.match(PAIR_PREFIX_RE)?.[1];
    const j = i + 1;
    if (prefix && j < items.length && items[j].label.startsWith(prefix + " \u2014 ")) {
      groups.push({ label: prefix, knobs: [items[i], items[j]] });
      i = j + 1;
    } else {
      groups.push({ label: "", knobs: [items[i]] });
      i++;
    }
  }
  return groups;
}

export function KnobPanel({ knobs, overrides, onChange }: Props) {
  const grouped = useMemo(() => {
    const map = new Map<KnobGroup, Knob[]>();
    for (const k of knobs) {
      const list = map.get(k.group) ?? [];
      list.push(k);
      map.set(k.group, list);
    }
    return map;
  }, [knobs]);

  return (
    <div className={classes.root}>
      {SECTIONS.map(({ group, title }) => {
        const items = grouped.get(group);
        if (!items || items.length === 0) return null;
        return (
          <KnobSection key={group} title={title}>
            {groupIntoPairs(items).map(({ label, knobs: groupKnobs }) => {
              const sliders = groupKnobs.map(knob => (
                <KnobSlider
                  key={knob.id}
                  label={knob.label}
                  value={overrides[knob.cssVar] ?? knob.defaultValue}
                  min={knob.min}
                  max={knob.max}
                  step={knob.step}
                  onChange={value => onChange(knob.id, value)}
                />
              ));

              if (!label) return sliders;

              return (
                <KnobGroup key={label} label={label}>
                  {sliders}
                </KnobGroup>
              );
            })}
          </KnobSection>
        );
      })}
    </div>
  );
}

